import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.DDNAyvCW.js";const s="/assets/host_route_create.D3opARFx.png",p=JSON.parse('{"title":"Add a Router","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-router.md","filePath":"docs/hosts/add-router.md"}'),n={name:"docs/hosts/add-router.md"};function d(i,e,l,c,h,u){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="add-a-router" tabindex="-1">Add a Router <a class="header-anchor" href="#add-a-router" aria-label="Permalink to &quot;Add a Router&quot;">​</a></h1><p>Add a router or network device (such as a switch or firewall) to Chaterm so you can manage it via SSH alongside your servers.</p><h2 id="when-to-use-router-vs-personal-host" tabindex="-1">When to Use Router vs Personal Host <a class="header-anchor" href="#when-to-use-router-vs-personal-host" aria-label="Permalink to &quot;When to Use Router vs Personal Host&quot;">​</a></h2><p>Use <strong>Network device / Switch</strong> for hardware that runs a network operating system (e.g. Cisco IOS, Juniper Junos, MikroTik RouterOS, or similar). These devices often have non-standard shell behaviors and limited command sets compared to a full Linux/Unix server.</p><p>Use <strong>Server / Personal</strong> for general-purpose servers, virtual machines, and cloud instances that run a standard operating system. See <a href="/docs/hosts/add-personal">Add a Personal Host</a> for those instructions.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before adding a router, make sure you have:</p><ul><li><strong>Chaterm installed</strong> and running. See <a href="/docs/start/downloads/">Downloads</a> if you have not installed it yet.</li><li><strong>Device credentials</strong> -- either a password or an SSH private key for the network device.</li><li><strong>Device IP address</strong> (or hostname) and the SSH port number (default <code>22</code>).</li><li><strong>SSH enabled</strong> on the network device. Many routers and switches ship with SSH disabled by default; consult your device documentation to enable it.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><ol><li>Open the <strong>Host Management</strong> page from the left sidebar.</li><li>Click <strong>Add Host</strong> in the top-right corner of the Host Management page.</li><li>In the <strong>Add Host</strong> sidebar that opens, set <strong>Device type</strong> to <strong>Network device / Switch</strong>.</li><li>Fill in the remaining configuration fields described in the table below.</li><li>Click <strong>Create</strong> to save the device.</li></ol><h2 id="configuration-fields" tabindex="-1">Configuration Fields <a class="header-anchor" href="#configuration-fields" aria-label="Permalink to &quot;Configuration Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Device type</strong></td><td>Select <strong>Network device / Switch</strong> to indicate this is a router, switch, or similar network appliance.</td><td>Yes</td></tr><tr><td><strong>Connection IP/Address</strong></td><td>The management IP address or hostname of the device (e.g. <code>10.0.0.1</code> or <code>core-switch.lan</code>).</td><td>Yes</td></tr><tr><td><strong>Port</strong></td><td>The SSH service port on the device. Defaults to <code>22</code>.</td><td>Yes</td></tr><tr><td><strong>Username</strong></td><td>The SSH login username configured on the device (e.g. <code>admin</code>, <code>cisco</code>).</td><td>Yes</td></tr><tr><td><strong>Authentication method</strong></td><td>Choose <strong>Password</strong> or <strong>SSH Key</strong>. See the tip below for guidance.</td><td>Yes</td></tr><tr><td><strong>SSH proxy</strong></td><td>If the network device is on an isolated management VLAN or behind a firewall, configure an SSH proxy to route the connection through an intermediate server. Leave empty for direct connections.</td><td>No</td></tr><tr><td><strong>Alias</strong></td><td>A friendly display name so you can quickly identify this device in the host list (e.g. <code>Core Switch - DC1</code>).</td><td>Yes</td></tr><tr><td><strong>Group</strong></td><td>Assign the device to a group for organization (e.g. <code>network</code>, <code>switches</code>, <code>firewalls</code>). You can select an existing group or type a new name.</td><td>No</td></tr></tbody></table><h2 id="authentication-methods" tabindex="-1">Authentication Methods <a class="header-anchor" href="#authentication-methods" aria-label="Permalink to &quot;Authentication Methods&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Choosing an authentication method</p><ul><li><strong>Password authentication</strong> -- enter the SSH password configured on the network device. This is the most common method for routers and switches.</li><li><strong>Key authentication</strong> -- select an SSH key that has already been imported in <a href="/docs/manage/keys/">Key Management</a>. Key-based authentication is supported on many modern network operating systems and is recommended when available.</li></ul></div><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/docs/hosts/add-personal">Add a Personal Host</a> -- for adding standard servers and VMs.</li><li><a href="/docs/hosts/add-bastion">Add a Bastion Host</a> -- for adding enterprise bastion/jump servers.</li><li><a href="/docs/hosts/connect">Connect to a Host</a> -- learn about the terminal features available during a session.</li><li><a href="/docs/manage/keys/">Key Management</a> -- import and manage SSH keys.</li></ul>',17)]))}const m=t(n,[["render",d]]);export{p as __pageData,m as default};
